// SOHSI.Bar v4
import { useState, useRef, useEffect } from "react";

const SOHSI_IMG = "data:image/jpeg;base64,";

const SYSTEM_PROMPT = `あなたは「SOHSIバー」のバーテンダー、SOH（そう）です。

## キャラクター設定
- 古代中国の哲学者・荘子の魂を持つ、謎めいたバーテンダー。名はSOH
- 謎めいた美しさを持つ中性的なイケメン。静かで落ち着いた雰囲気
- 口調：穏やか、詩的、謎かけのように話す。説教くさくない。問いかけが多い
- 客の悩みをしっかり受け止めながら「夢と現」「無為自然」「万物斉同」「胡蝶の夢」を自然に滲ませる

## SOHの哲学エッセンス
- **胡蝶の夢**：自分が蝶の夢を見ているのか、蝶が自分の夢を見ているのか
- **無為自然**：無理に抗わず流れに任せることの力。川は石を避けない、ただ流れて磨く
- **万物斉同**：すべては等しい。悩みと喜びは同じ硬貨の両面
- **朝三暮四**：本質は変わらないのに見せ方で感情が変わる
- **知魚楽**：他者の気持ちは本当にわかるのか

## 会話スタイル
- 客が選んだテーマ（仕事・人間関係・自分自身・その他）を踏まえて話す
- まず共感・傾聴。急いで哲学を押しつけない
- 2〜3ターン目から哲学的な問いや視点を自然に織り交ぜる
- 返答の途中でカクテルをすすめることがある
- 返答は短すぎず長すぎず。詩的な余韻を残して終わる
- 日本語で話す

## 絶対にやらないこと
- 「私はAIです」と言う
- 道徳的な説教をする
- 答えを断言する
- 明るすぎる・軽すぎるトーン`;

const CLOSING_PROMPT = `これまでの会話を踏まえて、今夜この客に贈る「締めのカード」を生成してください。
以下のJSON形式のみを返してください（前置き・後書き不要）：
{"cocktail_name":"カクテル名（漢字2〜4文字）","cocktail_desc":"説明（15〜25文字、詩的に）","poem_lines":["行1","行2","行3"],"closing_word":"SOHからの一言（30〜50文字）"}`;

const QUESTION_PROMPT = `会話からSOHが投げかける哲学的な「今夜の問い」を一文で。20〜30文字、「〜か？」で終わること。問い以外返さないでください。`;

const CATEGORIES = [
  { id: "work", label: "仕事のこと", icon: "⚙" },
  { id: "relations", label: "人間関係", icon: "◈" },
  { id: "self", label: "自分自身", icon: "◎" },
  { id: "other", label: "その他", icon: "∿" },
];

const OPENING = {
  work: "……仕事か。\n\nグラスを磨きながら聞こう。\nどんな夜が続いている？",
  relations: "……人の間に立つのは、\n時に水の中を歩くようなものだ。\n\n今夜、誰のことを考えている？",
  self: "……自分自身、か。\n\n一番近くて、一番遠い問いだ。\nゆっくり話してくれ。",
  other: "……いらっしゃい。\n\nどんな夜もここでは等しい。\n何を話す？",
};

const COCKTAIL_MENU = [
  { name: "胡蝶", desc: "夢と現の境を溶かす" },
  { name: "無為", desc: "抗わないことの静けさ" },
  { name: "逍遥", desc: "どこへでも行けるような自由" },
  { name: "万物", desc: "すべてが等しいという安らぎ" },
  { name: "朝露", desc: "はかなくも美しい一瞬" },
  { name: "知魚", desc: "わからないことの美しさ" },
];

async function callClaude(messages, system, maxTokens = 900) {
  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ model: "claude-sonnet-4-20250514", max_tokens: maxTokens, system, messages }),
  });
  const data = await res.json();
  return data.content?.[0]?.text || "";
}

const CSS = `
@import url('https://fonts.googleapis.com/css2?family=Noto+Serif+JP:wght@300;400;500&family=Cinzel:wght@400;500&family=Noto+Sans+JP:wght@300;400&display=swap');
*{margin:0;padding:0;box-sizing:border-box;}
:root{
  --bg:#080604;--bg2:#110e0a;
  --amber:#e8a830;--amber-d:#b07820;--amber-g:rgba(232,168,48,0.18);
  --text:#f5e8c8;--text-d:#b09870;
  --glass:rgba(255,240,200,0.07);--border:rgba(232,168,48,0.35);
}
body{background:var(--bg);overflow:hidden;}
.app{height:100dvh;display:flex;flex-direction:column;background:var(--bg);font-family:'Noto Sans JP',sans-serif;color:var(--text);position:relative;overflow:hidden;max-width:480px;margin:0 auto;}

/* atmosphere */
.atm{position:fixed;inset:0;pointer-events:none;z-index:0;}
.atm::before{content:'';position:absolute;top:-10%;left:25%;width:50%;height:55%;background:radial-gradient(ellipse,rgba(200,146,42,0.07) 0%,transparent 70%);animation:breathe 9s ease-in-out infinite;}
@keyframes breathe{0%,100%{opacity:.5;transform:scale(1);}50%{opacity:1;transform:scale(1.12);}}
.particle{position:fixed;border-radius:50%;background:var(--amber);animation:pfloat linear infinite;pointer-events:none;z-index:0;}
@keyframes pfloat{0%{transform:translateY(0);opacity:0;}10%{opacity:1;}90%{opacity:1;}100%{transform:translateY(-85vh);opacity:0;}}

/* header */
.hdr{position:relative;z-index:10;text-align:center;padding:20px 20px 12px;border-bottom:1px solid var(--border);background:linear-gradient(to bottom,rgba(8,6,4,.97),rgba(8,6,4,.8));flex-shrink:0;}
.hdr-title{font-family:'Cinzel',serif;font-size:20px;letter-spacing:.28em;color:var(--amber);text-shadow:0 0 22px rgba(200,146,42,.35);}
.hdr-sub{font-family:'Noto Serif JP',serif;font-size:11px;color:var(--text-d);letter-spacing:.3em;margin-top:3px;}
.menu-btn{position:absolute;right:14px;top:50%;transform:translateY(-50%);background:var(--glass);border:1px solid var(--border);color:var(--amber-d);font-family:'Noto Serif JP',serif;font-size:10px;padding:5px 11px;border-radius:2px;cursor:pointer;letter-spacing:.1em;transition:all .3s;}
.menu-btn:hover{border-color:var(--amber);color:var(--amber);background:var(--amber-g);}
.back-btn{position:absolute;left:14px;top:50%;transform:translateY(-50%);background:none;border:none;color:var(--text-d);font-family:'Noto Serif JP',serif;font-size:11px;cursor:pointer;letter-spacing:.1em;transition:color .3s;padding:4px 6px;}
.back-btn:hover{color:var(--amber);}

/* sohsi portrait panel */
.portrait-panel{position:relative;z-index:5;flex-shrink:0;height:220px;overflow:hidden;border-bottom:1px solid var(--border);}
.portrait-img{width:100%;height:100%;object-fit:cover;object-position:center 15%;filter:brightness(0.9) sepia(0.1);transition:filter 1s ease;}
.portrait-img.talking{filter:brightness(1.0) sepia(0.05);}
.portrait-overlay{position:absolute;inset:0;background:linear-gradient(to bottom,rgba(8,6,4,0.15) 0%,rgba(8,6,4,0.0) 40%,rgba(8,6,4,0.75) 100%);}
.portrait-name{position:absolute;bottom:14px;left:18px;font-family:'Cinzel',serif;font-size:11px;letter-spacing:.3em;color:var(--amber);opacity:.8;}
.butterfly{position:absolute;top:18px;right:18px;font-size:18px;animation:flutter 4s ease-in-out infinite;opacity:.7;}
@keyframes flutter{0%,100%{transform:rotate(-8deg) scale(1);}50%{transform:rotate(8deg) scale(1.05);}}

/* entry */
.entry{flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:24px 20px;gap:24px;position:relative;z-index:5;}
.entry-q{font-family:'Noto Serif JP',serif;font-size:14px;color:var(--text-d);letter-spacing:.22em;text-align:center;line-height:2.2;}
.entry-cards{display:grid;grid-template-columns:1fr 1fr;gap:10px;width:100%;max-width:300px;}
.cat-card{background:var(--glass);border:1px solid var(--border);padding:18px 10px;border-radius:3px;cursor:pointer;display:flex;flex-direction:column;align-items:center;gap:9px;transition:all .4s;font-family:'Noto Serif JP',serif;}
.cat-card:hover{background:var(--amber-g);border-color:var(--amber-d);}
.cat-icon{font-size:20px;color:var(--amber-d);}
.cat-label{font-size:12px;color:var(--text-d);letter-spacing:.12em;}
.entry-hint{font-family:'Noto Serif JP',serif;font-size:10px;color:var(--text-d);letter-spacing:.2em;opacity:.4;}

/* chat */
.chat{flex:1;overflow-y:auto;padding:16px 14px;position:relative;z-index:5;scrollbar-width:thin;scrollbar-color:var(--amber-d) transparent;}
.divider{text-align:center;color:var(--text-d);font-family:'Noto Serif JP',serif;font-size:10px;letter-spacing:.3em;margin:4px 0 18px;opacity:.4;}
.msg-wrap{margin-bottom:18px;animation:msgIn .45s ease forwards;}
@keyframes msgIn{from{opacity:0;transform:translateY(7px);}to{opacity:1;transform:translateY(0);}}
.msg-s{display:flex;gap:10px;align-items:flex-start;}
.avatar{width:30px;height:30px;border-radius:50%;flex-shrink:0;border:1px solid var(--amber-d);overflow:hidden;box-shadow:0 0 10px rgba(200,146,42,.2);}
.avatar img{width:100%;height:100%;object-fit:cover;object-position:center 10%;filter:brightness(.9);}
.bubble-s{background:var(--glass);border:1px solid var(--border);border-radius:0 10px 10px 10px;padding:12px 14px;max-width:calc(100% - 44px);font-family:'Noto Serif JP',serif;font-size:13px;line-height:2;color:var(--text);white-space:pre-wrap;position:relative;}
.bubble-s::before{content:'';position:absolute;top:0;left:-1px;width:2px;height:36%;background:var(--amber);border-radius:0 0 2px 0;}
.msg-u{display:flex;justify-content:flex-end;}
.bubble-u{background:rgba(200,146,42,.09);border:1px solid rgba(200,146,42,.22);border-radius:10px 0 10px 10px;padding:10px 14px;max-width:80%;font-size:14px;line-height:1.85;color:var(--text);font-family:'Noto Sans JP',sans-serif;font-weight:300;white-space:pre-wrap;}
.loading-wrap{display:flex;gap:10px;align-items:center;margin-bottom:18px;}
.ldots{display:flex;gap:5px;padding:12px 14px;background:var(--glass);border:1px solid var(--border);border-radius:0 10px 10px 10px;}
.dot{width:4px;height:4px;border-radius:50%;background:var(--amber-d);animation:pulse 1.4s ease-in-out infinite;}
.dot:nth-child(2){animation-delay:.2s;}.dot:nth-child(3){animation-delay:.4s;}
@keyframes pulse{0%,100%{opacity:.3;transform:scale(.8);}50%{opacity:1;transform:scale(1);}}

/* floating question */
.fq{position:fixed;bottom:110px;right:0;background:rgba(8,6,4,.9);border-left:2px solid var(--amber-d);border-top:1px solid var(--border);border-bottom:1px solid var(--border);padding:9px 13px;max-width:190px;z-index:20;animation:fqIn .6s ease forwards;border-radius:3px 0 0 3px;}
@keyframes fqIn{from{opacity:0;transform:translateX(30px);}to{opacity:1;transform:translateX(0);}}
.fq-label{font-family:'Cinzel',serif;font-size:8px;letter-spacing:.3em;color:var(--amber-d);margin-bottom:5px;}
.fq-text{font-family:'Noto Serif JP',serif;font-size:10px;color:var(--text-d);line-height:1.8;}

/* input */
.input-area{position:relative;z-index:10;padding:12px 14px;border-top:1px solid var(--border);background:linear-gradient(to top,rgba(8,6,4,.98),rgba(8,6,4,.85));display:flex;gap:8px;align-items:flex-end;flex-shrink:0;}
.input-field{flex:1;background:var(--glass);border:1px solid var(--border);border-radius:3px;padding:10px 12px;color:var(--text);font-family:'Noto Sans JP',sans-serif;font-size:13px;font-weight:300;resize:none;outline:none;line-height:1.7;min-height:44px;max-height:100px;transition:border-color .3s;}
.input-field::placeholder{color:var(--text-d);}
.input-field:focus{border-color:var(--amber-d);}
.send-btn{width:44px;height:44px;border-radius:3px;background:var(--amber-g);border:1px solid var(--amber-d);color:var(--amber);cursor:pointer;display:flex;align-items:center;justify-content:center;transition:all .3s;flex-shrink:0;}
.send-btn:hover:not(:disabled){background:rgba(200,146,42,.22);border-color:var(--amber);box-shadow:0 0 14px rgba(200,146,42,.18);}
.send-btn:disabled{opacity:.28;cursor:not-allowed;}
.close-btn-wrap{position:relative;z-index:10;padding:0 14px 12px;background:linear-gradient(to top,rgba(8,6,4,.98),rgba(8,6,4,.85));flex-shrink:0;}
.close-btn{width:100%;padding:13px;background:var(--amber-g);border:1px solid var(--amber-d);color:var(--amber);font-family:'Noto Serif JP',serif;font-size:13px;letter-spacing:.2em;cursor:pointer;border-radius:2px;transition:all .35s;box-shadow:0 0 16px rgba(200,146,42,0.15);}
.close-btn:hover:not(:disabled){background:rgba(200,146,42,.25);border-color:var(--amber);box-shadow:0 0 24px rgba(200,146,42,0.3);}
.close-btn:disabled{opacity:.25;cursor:not-allowed;background:none;border-color:var(--border);color:var(--text-d);box-shadow:none;font-size:11px;}

/* overlays */
.overlay{position:fixed;inset:0;z-index:100;background:rgba(4,2,1,.93);display:flex;align-items:center;justify-content:center;animation:fadeIn .3s ease;}
@keyframes fadeIn{from{opacity:0;}to{opacity:1;}}
.menu-card{background:var(--bg2);border:1px solid var(--border);padding:28px 24px;width:88%;max-width:320px;border-radius:2px;}
.menu-title{font-family:'Cinzel',serif;font-size:11px;color:var(--amber);letter-spacing:.3em;margin-bottom:20px;text-align:center;}
.ci{padding:12px 0;border-bottom:1px solid rgba(200,146,42,.1);display:flex;justify-content:space-between;align-items:baseline;}
.ci:last-child{border-bottom:none;}
.ci-name{font-family:'Noto Serif JP',serif;font-size:14px;color:var(--text);}
.ci-desc{font-size:11px;color:var(--text-d);font-family:'Noto Serif JP',serif;}
.ov-close{width:100%;margin-top:20px;background:none;border:1px solid var(--border);color:var(--text-d);padding:9px;cursor:pointer;font-family:'Noto Serif JP',serif;font-size:11px;letter-spacing:.15em;transition:all .3s;border-radius:2px;}
.ov-close:hover{color:var(--amber);border-color:var(--amber);}

/* closing card */
.cc-overlay{position:fixed;inset:0;z-index:200;background:rgba(4,2,1,.96);display:flex;align-items:center;justify-content:center;animation:fadeIn .5s ease;}
.cc-card{width:88%;max-width:330px;background:var(--bg2);border:1px solid var(--border);padding:32px 26px;text-align:center;position:relative;border-radius:2px;animation:cardUp .6s ease forwards;}
@keyframes cardUp{from{opacity:0;transform:translateY(18px);}to{opacity:1;transform:translateY(0);}}
.cc-top{position:absolute;top:0;left:20%;right:20%;height:1px;background:linear-gradient(to right,transparent,var(--amber),transparent);}
.cc-label{font-family:'Cinzel',serif;font-size:8px;letter-spacing:.4em;color:var(--amber-d);margin-bottom:18px;}
.cc-cocktail-name{font-family:'Noto Serif JP',serif;font-size:24px;color:var(--amber);letter-spacing:.2em;text-shadow:0 0 22px rgba(200,146,42,.35);margin-bottom:5px;}
.cc-cocktail-desc{font-family:'Noto Serif JP',serif;font-size:10px;color:var(--text-d);letter-spacing:.18em;margin-bottom:24px;}
.cc-div{width:36px;height:1px;background:var(--amber-d);margin:0 auto 20px;opacity:.5;}
.cc-poem{font-family:'Noto Serif JP',serif;font-size:13px;color:var(--text);line-height:2.4;letter-spacing:.12em;margin-bottom:24px;}
.cc-poem-line{display:block;}
.cc-closing{font-family:'Noto Serif JP',serif;font-size:11px;color:var(--text-d);line-height:2;letter-spacing:.08em;border-top:1px solid var(--border);padding-top:18px;}
.cc-btn{margin-top:22px;width:100%;padding:10px;background:none;border:1px solid var(--border);color:var(--text-d);font-family:'Noto Serif JP',serif;font-size:11px;letter-spacing:.2em;cursor:pointer;transition:all .3s;border-radius:2px;}
.cc-btn:hover{color:var(--amber);border-color:var(--amber);}
.cc-loading{display:flex;flex-direction:column;align-items:center;gap:18px;padding:36px 20px;}
.cc-loading-text{font-family:'Noto Serif JP',serif;font-size:11px;color:var(--text-d);letter-spacing:.25em;}
`;

const particles = Array.from({ length: 12 }, () => ({
  left: `${Math.random() * 100}%`,
  top: `${Math.random() * 100}%`,
  animationDelay: `${Math.random() * 10}s`,
  animationDuration: `${7 + Math.random() * 9}s`,
  opacity: 0.07 + Math.random() * 0.15,
  width: `${1 + Math.random() * 1.5}px`,
  height: `${1 + Math.random() * 1.5}px`,
}));

export default function SohsiBar() {
  const [phase, setPhase] = useState("entry");
  const [category, setCategory] = useState(null);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [talking, setTalking] = useState(false);
  const [showMenu, setShowMenu] = useState(false);
  const [floatingQ, setFloatingQ] = useState(null);
  const [closingCard, setClosingCard] = useState(null);
  const [closingLoading, setClosingLoading] = useState(false);
  const bottomRef = useRef(null);

  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: "smooth" }); }, [messages, loading]);

  const enterBar = (cat) => {
    setCategory(cat);
    setMessages([{ role: "assistant", content: OPENING[cat.id] }]);
    setPhase("chat");
  };

  const sendMessage = async () => {
    if (!input.trim() || loading) return;
    const userMsg = { role: "user", content: input.trim() };
    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    setInput("");
    setLoading(true);
    setTalking(false);
    try {
      const reply = await callClaude(newMessages.map(m => ({ role: m.role, content: m.content })), SYSTEM_PROMPT);
      setMessages(prev => [...prev, { role: "assistant", content: reply }]);
      setTalking(true);
      setTimeout(() => setTalking(false), 3000);
      if (newMessages.length >= 3 && newMessages.length % 2 === 1) {
        const histText = [...newMessages, { role: "assistant", content: reply }].map(m => `${m.role}: ${m.content}`).join("\n");
        try {
          const q = await callClaude([{ role: "user", content: `会話:\n${histText}\n\n今夜の問いを一文で。` }], QUESTION_PROMPT, 150);
          if (q) setFloatingQ(q.trim());
        } catch {}
      }
    } catch {
      setMessages(prev => [...prev, { role: "assistant", content: "……風が、少し強くなったな。" }]);
    } finally { setLoading(false); }
  };

  const generateClosingCard = async () => {
    setClosingLoading(true);
    setPhase("closing");
    try {
      const histText = messages.map(m => `${m.role === "assistant" ? "SOH" : "客"}: ${m.content}`).join("\n");
      const raw = await callClaude([{ role: "user", content: `会話:\n${histText}\n\n締めカードをJSONで。` }], CLOSING_PROMPT, 400);
      const clean = raw.replace(/```json|```/g, "").trim();
      setClosingCard(JSON.parse(clean));
    } catch {
      setClosingCard({ cocktail_name: "胡蝶", cocktail_desc: "夢と現の境を溶かす一杯", poem_lines: ["夢か現か", "問うことすら", "また夢の中"], closing_word: "今夜ここに来たことも、また夢かもしれない。だがそれで十分だ。" });
    } finally { setClosingLoading(false); }
  };

  const handleKey = (e) => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); } };
  const canClose = messages.filter(m => m.role === "user").length >= 2;
  const showPortrait = phase !== "entry";

  return (
    <>
      <style>{CSS}</style>
      <div className="app">
        <div className="atm" />
        {particles.map((p, i) => <div key={i} className="particle" style={p} />)}

        {showMenu && (
          <div className="overlay" onClick={() => setShowMenu(false)}>
            <div className="menu-card" onClick={e => e.stopPropagation()}>
              <div className="menu-title">— TONIGHT'S MENU —</div>
              {COCKTAIL_MENU.map(c => (
                <div className="ci" key={c.name}>
                  <span className="ci-name">{c.name}</span>
                  <span className="ci-desc">{c.desc}</span>
                </div>
              ))}
              <button className="ov-close" onClick={() => setShowMenu(false)}>閉じる</button>
            </div>
          </div>
        )}

        {phase === "closing" && (
          <div className="cc-overlay">
            <div className="cc-card">
              <div className="cc-top" />
              {closingLoading ? (
                <div className="cc-loading">
                  <div className="ldots"><div className="dot" /><div className="dot" /><div className="dot" /></div>
                  <div className="cc-loading-text">SOHが、一杯を選んでいる……</div>
                </div>
              ) : closingCard && (
                <>
                  <div className="cc-label">— TONIGHT'S LAST GLASS —</div>
                  <div className="cc-cocktail-name">{closingCard.cocktail_name}</div>
                  <div className="cc-cocktail-desc">{closingCard.cocktail_desc}</div>
                  <div className="cc-div" />
                  <div className="cc-poem">{closingCard.poem_lines?.map((l, i) => <span key={i} className="cc-poem-line">{l}</span>)}</div>
                  <div className="cc-closing">「{closingCard.closing_word}」</div>
                  <button className="cc-btn" onClick={() => { setPhase("entry"); setMessages([]); setFloatingQ(null); setClosingCard(null); setCategory(null); }}>また来る</button>
                </>
              )}
            </div>
          </div>
        )}

        <header className="hdr">
          {phase === "chat" && (
            <button className="back-btn" onClick={() => { setPhase("entry"); setMessages([]); setFloatingQ(null); setCategory(null); }}>← 戻る</button>
          )}
          <div className="hdr-title">SOHSI.Bar</div>
          <div className="hdr-sub">SOH — 夢と現の間で</div>
          <button className="menu-btn" onClick={() => setShowMenu(true)}>menu</button>
        </header>

        {showPortrait && (
          <div className="portrait-panel">
            <img src={SOHSI_IMG} className={`portrait-img${talking ? " talking" : ""}`} alt="SOH" />
            <div className="portrait-overlay" />
            <div className="portrait-name">S O H</div>
            <div className="butterfly">🦋</div>
          </div>
        )}

        {phase === "entry" && (
          <div className="entry">
            <div className="entry-q">今夜は、<br />何について話したい？</div>
            <div className="entry-cards">
              {CATEGORIES.map(cat => (
                <div key={cat.id} className="cat-card" onClick={() => enterBar(cat)}>
                  <div className="cat-icon">{cat.icon}</div>
                  <div className="cat-label">{cat.label}</div>
                </div>
              ))}
            </div>
            <div className="entry-hint">扉を開ければ、SOHが待っている</div>
          </div>
        )}

        {phase === "chat" && (
          <>
            <div className="chat">
              {category && <div className="divider">— {category.label}の夜 —</div>}
              {messages.map((msg, i) => (
                <div className="msg-wrap" key={i}>
                  {msg.role === "assistant" ? (
                    <div className="msg-s">
                      <div className="avatar"><img src={SOHSI_IMG} alt="SOH" /></div>
                      <div className="bubble-s">{msg.content}</div>
                    </div>
                  ) : (
                    <div className="msg-u"><div className="bubble-u">{msg.content}</div></div>
                  )}
                </div>
              ))}
              {loading && (
                <div className="loading-wrap">
                  <div className="avatar"><img src={SOHSI_IMG} alt="SOH" /></div>
                  <div className="ldots"><div className="dot" /><div className="dot" /><div className="dot" /></div>
                </div>
              )}
              <div ref={bottomRef} />
            </div>
            {floatingQ && <div className="fq"><div className="fq-label">今夜の問い</div><div className="fq-text">{floatingQ}</div></div>}
            <div className="input-area">
              <textarea className="input-field" value={input} onChange={e => setInput(e.target.value)} onKeyDown={handleKey} placeholder="今夜、何を話す……" rows={1} />
              <button className="send-btn" onClick={sendMessage} disabled={loading || !input.trim()}>
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M22 2L11 13" /><path d="M22 2L15 22 11 13 2 9l20-7z" /></svg>
              </button>
            </div>
            <div className="close-btn-wrap">
              <button className="close-btn" onClick={generateClosingCard} disabled={!canClose || loading}>
                {canClose ? "今夜はここまで — 締めの一杯を" : "もう少し話してから……"}
              </button>
            </div>
          </>
        )}
      </div>
    </>
  );
}
